// src/components/BreadcrumbNav.js
import React from 'react';
import { useLocation, Link } from 'react-router-dom';
import { FaHome, FaChevronRight } from 'react-icons/fa';

const BreadcrumbNav = () => {
  const location = useLocation();
  const pathnames = location.pathname.split('/').filter(x => x);

  // Define readable names for IDs
  const courseNames = {
    '1': 'B.Tech',
    '2': 'BCA', 
    '3': 'BBA',
    '4': 'MBA',
    '5': 'MCA'
  };

  const getBreadcrumbName = (segment, index) => {
    const segments = location.pathname.split('/');
    const currentIndex = segments.indexOf(segment);
    
    switch(segment) {
      case 'course':
        const courseId = segments[currentIndex + 1];
        return courseNames[courseId] || 'Course';
      case 'year':
        const yearId = segments[currentIndex + 1];
        return `Year ${yearId}`;
      case 'sem':
        const semId = segments[currentIndex + 1];
        return `Semester ${semId}`;
      case 'subject':
        const subjectId = segments[currentIndex + 1];
        return 'Subject';
      default:
        // Convert to readable format
        return segment.charAt(0).toUpperCase() + segment.slice(1).replace(/-/g, ' ');
    }
  };

  // Don't show breadcrumb on homepage
  if (location.pathname === '/') return null;

  return (
    <nav style={styles.breadcrumb}>
      <Link to="/" style={styles.homeLink}>
        <FaHome /> Home
      </Link>
      
      {pathnames.map((segment, index) => {
        const routeTo = `/${pathnames.slice(0, index + 1).join('/')}`;
        const isLast = index === pathnames.length - 1;
        const displayName = getBreadcrumbName(segment, index);

        return (
          <span key={segment} style={styles.breadcrumbItem}>
            <FaChevronRight style={styles.chevron} />
            {isLast ? (
              <span style={styles.current}>{displayName}</span>
            ) : (
              <Link to={routeTo} style={styles.link}>
                {displayName}
              </Link>
            )}
          </span>
        );
      })}
    </nav>
  );
};

const styles = {
  breadcrumb: {
    display: 'flex',
    alignItems: 'center',
    gap: '0.5rem',
    padding: '1rem 2rem',
    background: 'white',
    borderBottom: '1px solid #e5e7eb',
    fontSize: '0.9rem',
    color: '#6b7280',
    flexWrap: 'wrap'
  },
  homeLink: {
    display: 'flex',
    alignItems: 'center',
    gap: '0.5rem',
    color: '#4f46e5',
    textDecoration: 'none',
    fontWeight: '500',
    '&:hover': {
      textDecoration: 'underline'
    }
  },
  breadcrumbItem: {
    display: 'flex',
    alignItems: 'center',
    gap: '0.5rem'
  },
  chevron: {
    color: '#9ca3af',
    fontSize: '0.8rem'
  },
  link: {
    color: '#4f46e5',
    textDecoration: 'none',
    '&:hover': {
      textDecoration: 'underline'
    }
  },
  current: {
    color: '#1f2937',
    fontWeight: '500'
  }
};

export default BreadcrumbNav;
